    for i in 0..<landStartTime.count {
        for j in 0..<waterStartTime.count {
            // Land first then water
            let landEnd = landStartTime[i] + landDuration[i]
            let waterStart = max(waterStartTime[j], landEnd)
            let scenario1 = waterStart + waterDuration[j]

            // Water first then land
            let waterEnd = waterStartTime[j] + waterDuration[j]
            let landStart = max(landStartTime[i], waterEnd)
            let scenario2 = landStart + landDuration[i]

            let currentMin = min(scenario1, scenario2)
            if currentMin < minTime {
                minTime = currentMin
            }
        }
    }
